@Test
public void testOrderCreationWithInvalidAmount() {
    String invalidOrderJson = "{"
        + "\"amount\": \"not_a_number\","
        + "\"productId\": 1,"
        + "\"quantity\": 2"
        + "}";

    ResponseEntity<String> response = testRestTemplate.postForEntity(
        "/api/orders", 
        new HttpEntity<>(invalidOrderJson, headers), 
        String.class
    );

    assertEquals(400, response.getStatusCodeValue());
    assertTrue(response.getBody().contains("Invalid amount format"));
}

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(HttpMessageNotReadableException.class)
    public ResponseEntity<ErrorResponse> handleJsonParseException(
            HttpMessageNotReadableException ex) {

        String message = "Invalid request format";
        if (ex.getCause() instanceof InvalidFormatException) {
            InvalidFormatException ife = (InvalidFormatException) ex.getCause();
            if (ife.getTargetType().equals(BigDecimal.class)) {
                message = "Invalid amount format. Please provide a valid number";
            }
        }

        ErrorResponse error = new ErrorResponse(
            "INVALID_INPUT", 
            message,
            Instant.now()
        );

        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }
}

