@Component
public class SafeBigDecimalDeserializer extends JsonDeserializer<BigDecimal> {
    @Override
    public BigDecimal deserialize(JsonParser p, DeserializationContext ctx) 
            throws IOException {
        String value = p.getValueAsString();
        try {
            return new BigDecimal(value);
        } catch (NumberFormatException e) {
            throw new InvalidFormatException(p, 
                "Invalid decimal format: " + value, 
                value, BigDecimal.class);
        }
    }
}
